"use client";

import { Sparkles } from "lucide-react";
import { sanitizeNewsTitle } from "@/lib/sanitizeTitle";

interface AiSummaryProps {
  title: string;
  aiSummary: string;
}

/** AI 분석 텍스트를 섹션별로 파싱 */
function parseSections(text: string): { summary: string; sections: { title: string; content: string }[] } {
  if (!text?.trim()) return { summary: "", sections: [] };

  // 구버전 캐시에 포함된 프롬프트 아티팩트 제거
  const cleaned = text
    .replace(/\[뉴스 심층 분석 양식\]/g, "")
    .replace(/^---+$/gm, "")
    .replace(/\n{3,}/g, "\n\n")
    .trim();

  const parts = cleaned.split(/(?=^[📌🔍⚡💡])/m).filter(Boolean);

  let summary = "";
  const sections: { title: string; content: string }[] = [];

  for (const part of parts) {
    const firstLine = part.split("\n")[0]?.trim() ?? "";
    const content = part.split("\n").slice(1).join("\n").trim();

    if (firstLine.includes("핵심 팩트") || firstLine.startsWith("📌")) {
      summary = content;
    } else if (firstLine) {
      sections.push({ title: firstLine, content });
    }
  }

  // 섹션으로 파싱이 안 되면 전체를 요약으로
  if (!summary && sections.length === 0) {
    summary = text.trim();
  }

  return { summary, sections };
}

export default function AiSummary({ title, aiSummary }: AiSummaryProps) {
  const { summary, sections } = parseSections(aiSummary);

  return (
    <>
      <h1 className="text-2xl font-bold">{sanitizeNewsTitle(title)}</h1>

      {/* 뉴스 요약 (핵심 팩트) */}
      {summary && (
        <div className="bg-skyblue/10 border border-skyblue/30 rounded-xl p-5">
          <div className="flex items-center gap-2 mb-3">
            <Sparkles className="w-5 h-5 text-skyblue" />
            <h2 className="font-bold text-skyblue">📌 한눈에 보는 핵심 팩트</h2>
          </div>
          <div className="text-gray-200 leading-relaxed whitespace-pre-wrap">{summary}</div>
        </div>
      )}

      {/* 항목별 분석 카드 */}
      {sections.length > 0 && (
        <div className="space-y-3">
          {sections.map((sec, i) => (
            <div
              key={i}
              className="bg-white/5 border border-white/10 rounded-xl p-4"
            >
              <h3 className="font-bold text-skyblue mb-2 text-sm">{sec.title}</h3>
              <div className="text-gray-200 text-sm leading-relaxed whitespace-pre-wrap">
                {sec.content}
              </div>
            </div>
          ))}
        </div>
      )}

    </>
  );
}
